import { Component, signal } from '@angular/core';

type Status = 'loading' | 'success' | 'error' | 'empty';

@Component({
  selector: 'app-status-card',
  standalone: true,
  template: `
    <!-- Basic @if / @else -->
    @if (isLoggedIn()) {
      <p>Welcome back, {{ username() }}!</p>
    } @else {
      <p>Please sign in to continue.</p>
    }

    <!-- @else if chain -->
    @if (status() === 'loading') {
      <div class="spinner">Loading...</div>

    } @else if (status() === 'error') {
      <div class="error">Something went wrong. <button (click)="retry()">Retry</button></div>

    } @else if (status() === 'empty') {
      <div class="empty">No results found.</div>

    } @else {
      <div class="content">Data loaded successfully ✓</div>
    }

    <!-- Unwrap a nullable value with @if -->
    @if (user(); as u) {
      <!-- 'u' is narrowed to non-null inside this block -->
      <h2>{{ u.name }}</h2>
      <p>{{ u.email }}</p>
    }
  `,
})
export class StatusCardComponent {
  isLoggedIn = signal(false);
  username   = signal('Ada Lovelace');
  status     = signal<Status>('loading');
  user       = signal<{ name: string; email: string } | null>(null);

  retry(): void {
    this.status.set('loading');
    // ... retry logic
  }
}

import { Component, signal } from '@angular/core';

interface Task {
  id: number;
  title: string;
  done: boolean;
  priority: 'low' | 'medium' | 'high';
}

@Component({
  selector: 'app-task-list',
  standalone: true,
  template: `
    <h2>Tasks ({{ tasks().length }})</h2>

    @for (task of tasks(); track task.id) {
      <!--                  ↑ track by unique id — required! -->

      <div [class.done]="task.done">
        <!-- $index, $first, $last built-in variables -->
        <span class="number">{{ $index + 1 }}.</span>

        <input type="checkbox" [checked]="task.done"
               (change)="toggleTask(task.id)" />

        <span>{{ task.title }}</span>

        <!-- $first / $last for special styling -->
        @if ($first) { <span class="badge">First</span> }
        @if ($last)  { <span class="badge">Last</span>  }

        <!-- $even / $odd for zebra striping -->
        <div [class.stripe]="$even">{{ task.priority }}</div>
      </div>

    } @empty {
      <!-- Rendered automatically when tasks() is an empty array -->
      <div class="empty-state">
        <p>No tasks yet! Add one to get started.</p>
      </div>
    }

    <button (click)="addTask()">+ Add Task</button>
    <button (click)="clearAll()">Clear All</button>
  `,
})
export class TaskListComponent {
  tasks = signal<Task[]>([
    { id: 1, title: 'Learn @for syntax',   done: true,  priority: 'high'   },
    { id: 2, title: 'Build a component',   done: false, priority: 'medium' },
    { id: 3, title: 'Deploy to Netlify',   done: false, priority: 'low'    },
  ]);

  toggleTask(id: number): void {
    this.tasks.update(list =>
      list.map(t => t.id === id ? { ...t, done: !t.done } : t)
    );
  }

  addTask(): void {
    const newId = Date.now();
    this.tasks.update(list => [
      ...list,
      { id: newId, title: 'New task', done: false, priority: 'medium' }
    ]);
  }

  clearAll(): void {
    this.tasks.set([]);   // triggers @empty block
  }
}

import { Component, signal } from '@angular/core';

type OrderStatus = 'pending' | 'processing' | 'shipped' | 'delivered' | 'cancelled';

@Component({
  selector: 'app-order-status',
  standalone: true,
  template: `
    <!-- @switch evaluates once and matches with === -->
    @switch (status()) {

      @case ('pending') {
        <div class="badge yellow">⏳ Pending</div>
        <p>Your order is awaiting confirmation.</p>
      }

      @case ('processing') {
        <div class="badge blue">⚙️ Processing</div>
        <p>We are preparing your order.</p>
      }

      @case ('shipped') {
        <div class="badge purple">🚚 Shipped</div>
        <p>Your order is on the way!</p>
      }

      @case ('delivered') {
        <div class="badge green">✅ Delivered</div>
        <p>Order delivered. Enjoy!</p>
      }

      @case ('cancelled') {
        <div class="badge red">❌ Cancelled</div>
        <p>This order was cancelled.</p>
      }

      @default {
        <div class="badge grey">❓ Unknown</div>
        <p>Status not recognised.</p>
      }
    }

    <!-- Cycle through statuses for demo -->
    <button (click)="nextStatus()">Next Status →</button>
  `,
})
export class OrderStatusComponent {
  private statuses: OrderStatus[] =
    ['pending', 'processing', 'shipped', 'delivered', 'cancelled'];
  private index = 0;

  status = signal<OrderStatus>('pending');

  nextStatus(): void {
    this.index = (this.index + 1) % this.statuses.length;
    this.status.set(this.statuses[this.index]);
  }
}

import { Component, signal } from '@angular/core';
import { NgClass } from '@angular/common';   // import NgClass!

@Component({
  selector: 'app-button-demo',
  standalone: true,
  imports: [NgClass],
  template: `
    <!-- Object syntax — most common -->
    <button
      [ngClass]="{
        'btn-primary':  variant() === 'primary',
        'btn-danger':   variant() === 'danger',
        'btn-outline':  outlined(),
        'btn-disabled': disabled(),
        'btn-lg':       size() === 'lg',
        'btn-sm':       size() === 'sm'
      }"
      [disabled]="disabled()"
    >
      Click me
    </button>

    <!-- Array syntax -->
    <div [ngClass]="['card', 'shadow', elevated() ? 'elevated' : '']">
      Card content
    </div>

    <!-- String syntax (static string from a computed signal) -->
    <span [ngClass]="badgeClasses()">Badge</span>

    <!-- Controls for demo -->
    <select (change)="variant.set($any($event.target).value)">
      <option value="primary">Primary</option>
      <option value="danger">Danger</option>
    </select>
    <label>
      <input type="checkbox" (change)="outlined.update(v => !v)" /> Outlined
    </label>
  `,
})
export class ButtonDemoComponent {
  variant  = signal<'primary' | 'danger'>('primary');
  outlined = signal(false);
  disabled = signal(false);
  size     = signal<'sm' | 'md' | 'lg'>('md');
  elevated = signal(true);

  badgeClasses = () =>
    `badge badge-${this.variant()} ${this.outlined() ? 'badge-outline' : ''}`;
}

import { Component, signal, computed } from '@angular/core';
import { NgStyle } from '@angular/common';

@Component({
  selector: 'app-progress',
  standalone: true,
  imports: [NgStyle],
  template: `
    <!-- ✓ Good use: dynamic value from runtime data -->
    <div class="progress-track">
      <div
        class="progress-fill"
        [ngStyle]="progressStyles()"
      ></div>
    </div>
    <p>{{ percent() }}% complete</p>

    <!-- ✓ Good use: position from data (e.g., map marker) -->
    <div
      class="marker"
      [ngStyle]="{ top: markerY() + 'px', left: markerX() + 'px' }"
    >
      📍
    </div>

    <!-- Controls -->
    <input type="range" min="0" max="100"
           [value]="percent()"
           (input)="percent.set(+$any($event.target).value)" />
  `,
})
export class ProgressComponent {
  percent = signal(42);
  markerX = signal(120);
  markerY = signal(80);

  progressStyles = computed(() => ({
    width:           this.percent() + '%',
    backgroundColor: this.percent() < 33 ? '#ef4444' :
                     this.percent() < 66 ? '#f59e0b' : '#22c55e',
    transition:      'all 0.3s ease',
  }));
}

import {
  Directive, HostListener, HostBinding,
  inject, ElementRef, input
} from '@angular/core';

/**
 * Usage: <p appHighlight highlightColor="#fef08a">Hover me!</p>
 *        <p appHighlight>Default yellow highlight</p>
 */
@Directive({
  selector: '[appHighlight]',   // attribute selector — applied to any element
  standalone: true,
})
export class HighlightDirective {
  // Optional input: the colour to highlight with
  highlightColor = input<string>('#fef08a');   // default: yellow

  private el = inject(ElementRef);            // reference to the host DOM element

  // HostBinding — binds host element's style.backgroundColor to this field
  @HostBinding('style.backgroundColor') bgColor = 'transparent';
  @HostBinding('style.transition')      transition = 'background-color 0.2s';

  // HostListener — listens to events on the host element
  @HostListener('mouseenter') onMouseEnter(): void {
    this.bgColor = this.highlightColor();
  }

  @HostListener('mouseleave') onMouseLeave(): void {
    this.bgColor = 'transparent';
  }

  @HostListener('click') onClick(): void {
    // Direct DOM access via ElementRef when needed
    this.el.nativeElement.style.outline = '2px solid ' + this.highlightColor();
    setTimeout(() => {
      this.el.nativeElement.style.outline = '';
    }, 600);
  }
}

