import { Directive, inject, ElementRef, AfterViewInit } from '@angular/core';

/**
 * Automatically focuses the host element after it appears in the DOM.
 * Usage: <input appAutofocus type="text" />
 */
@Directive({
  selector: '[appAutofocus]',
  standalone: true,
})
export class AutofocusDirective implements AfterViewInit {
  private el = inject(ElementRef);

  ngAfterViewInit(): void {
    // Use setTimeout to ensure the browser's event loop is clear
    // before attempting focus — important inside modals and @if blocks
    setTimeout(() => this.el.nativeElement.focus(), 0);
  }
}

